<w:p w:rsidR="0086767C" w:rsidRPr="0086767C" w:rsidRDefault="0086767C" w:rsidP="0086767C"><w:pPr><w:rPr><w:sz w:val="13"/><w:szCs w:val="13"/></w:rPr></w:pPr><w:r w:rsidRPr="0086767C"><w:rPr><w:sz w:val="13"/><w:szCs w:val="13"/></w:rPr><w:t>3. неизпълнение на други негови нареждания.</w:t></w:r></w:p>
